import os
import sys
import tarfile
import zipfile
import subprocess

def backup(directory, format):
    if format == "tar.gz":
        with tarfile.open("{}.tar.gz".format(directory), "w:gz") as tar:
            tar.add(directory)
    elif format == "tar.bz2":
        with tarfile.open("{}.tar.bz2".format(directory), "w:bz2") as tar:
            tar.add(directory)
    elif format == "zip":
        with zipfile.ZipFile("{}.zip".format(directory), "w", compression=zipfile.ZIP_DEFLATED) as zip:
            zip.write(directory)
    elif format == "7z":
        subprocess.run(["7z", "a", "{}.7z".format(directory), directory])
    else:
        print("Invalid format")